using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public static class Downloader
{
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        ArgumentNullException.ThrowIfNull(uris);
        ArgumentNullException.ThrowIfNull(fetch);

        var uriList = uris as IList<Uri> ?? uris.ToList();

        cancellationToken.ThrowIfCancellationRequested();

        var tasks = new Task<string>[uriList.Count];
        for (int i = 0; i < uriList.Count; i++)
        {
            tasks[i] = fetch(uriList[i], cancellationToken);
        }

        try
        {
            return await Task.WhenAll(tasks).ConfigureAwait(false);
        }
        catch
        {
            // If cancellation was requested, prefer surfacing an OperationCanceledException
            // that is tied to the provided token, regardless of which exception "won" the race.
            if (cancellationToken.IsCancellationRequested)
            {
                cancellationToken.ThrowIfCancellationRequested();
            }

            throw;
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public static class Downloader
{
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        if (uris is null) throw new ArgumentNullException(nameof(uris));
        if (fetch is null) throw new ArgumentNullException(nameof(fetch));

        cancellationToken.ThrowIfCancellationRequested();

        var tasks = uris.Select(uri => fetch(uri, cancellationToken)).ToArray();

        var whenAllTask = Task.WhenAll(tasks);

        var cancellationTcs = new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);
        await using (cancellationToken.Register(() => cancellationTcs.TrySetCanceled(cancellationToken)))
        {
            var completed = await Task.WhenAny(whenAllTask, cancellationTcs.Task).ConfigureAwait(false);

            if (completed == cancellationTcs.Task)
            {
                // Ensure we observe the cancellation and propagate as OperationCanceledException.
                await cancellationTcs.Task.ConfigureAwait(false);
            }
        }

        return await whenAllTask.ConfigureAwait(false);
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public static class Downloader
{
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        if (uris is null) throw new ArgumentNullException(nameof(uris));
        if (fetch is null) throw new ArgumentNullException(nameof(fetch));

        var uriList = uris as IList<Uri> ?? uris.ToList();
        var results = new string[uriList.Count];

        var fetchTasks = new Task[uriList.Count];
        for (int i = 0; i < uriList.Count; i++)
        {
            fetchTasks[i] = FetchAndStoreAsync(uriList[i], i, fetch, cancellationToken, results);
        }

        var allTask = Task.WhenAll(fetchTasks);

        // A task that completes (in a cancelled state) as soon as the token is cancelled,
        // allowing us to stop promptly without waiting for all fetches to finish.
        var cancellationTask = Task.Delay(Timeout.Infinite, cancellationToken);

        var completed = await Task.WhenAny(allTask, cancellationTask).ConfigureAwait(false);

        if (completed == cancellationTask && cancellationToken.IsCancellationRequested)
        {
            throw new OperationCanceledException(cancellationToken);
        }

        // Ensure any exceptions from the fetch tasks are properly propagated.
        await allTask.ConfigureAwait(false);

        return results;
    }

    private static async Task FetchAndStoreAsync(
        Uri uri,
        int index,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken,
        string[] results)
    {
        var result = await fetch(uri, cancellationToken).ConfigureAwait(false);
        results[index] = result;
    }
}

