using System.Threading.Tasks;

public static class Pipeline
{
    public static async Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count <= 0)
        {
            return 0L;
        }

        var channel = Channel.CreateBounded<int>(new BoundedChannelOptions(Math.Max(1, Math.Min(count, 100)))
        {
            SingleReader = true,
            SingleWriter = true,
            FullMode = BoundedChannelFullMode.Wait
        });

        var producerTask = Task.Run(async () =>
        {
            Exception? error = null;
            try
            {
                for (int i = 0; i < count; i++)
                {
                    await channel.Writer.WriteAsync(i).ConfigureAwait(false);
                }
            }
            catch (Exception ex)
            {
                error = ex;
            }
            finally
            {
                channel.Writer.Complete(error);
            }
        });

        long sum = 0;
        var reader = channel.Reader;
        while (await reader.WaitToReadAsync().ConfigureAwait(false))
        {
            while (reader.TryRead(out int item))
            {
                sum += item;
            }
        }

        await producerTask.ConfigureAwait(false);

        return sum;
    }
}

