public static class SpanParser
{
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int sum = 0;
        ReadOnlySpan<char> remaining = csv.Trim();

        if (remaining.IsEmpty)
        {
            return 0;
        }

        while (true)
        {
            int commaIndex = remaining.IndexOf(',');
            ReadOnlySpan<char> token;

            if (commaIndex == -1)
            {
                token = remaining;
            }
            else
            {
                token = remaining[..commaIndex];
            }

            token = token.Trim();
            if (!token.IsEmpty)
            {
                sum += int.Parse(token);
            }

            if (commaIndex == -1)
            {
                break;
            }

            remaining = remaining[(commaIndex + 1)..];
        }

        return sum;
    }
}

